<link href="https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Outfit:wght@400;600;700;800&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.2/css/all.min.css">
<style>
*{margin:0;padding:0;box-sizing:border-box;}
:root{--bg:#060610;--card:#0d0d20;--accent:#00d4ff;--accent2:#ff4466;--green:#00ff88;--gold:#ffd700;--text:#fff;--muted:#7788aa;--border:rgba(255,255,255,0.07);}
html{scroll-behavior:smooth;}
body{background:var(--bg);color:var(--text);font-family:'Outfit',sans-serif;overflow-x:hidden;}
.bg-grid{position:fixed;inset:0;z-index:0;background-image:linear-gradient(rgba(0,212,255,0.03) 1px,transparent 1px),linear-gradient(90deg,rgba(0,212,255,0.03) 1px,transparent 1px);background-size:40px 40px;}
nav{position:sticky;top:0;z-index:100;background:rgba(6,6,16,0.9);backdrop-filter:blur(20px);border-bottom:1px solid var(--border);padding:14px 20px;display:flex;align-items:center;justify-content:space-between;}
.nl{font-family:'Bebas Neue',sans-serif;font-size:22px;letter-spacing:4px;background:linear-gradient(135deg,var(--accent),#0066aa);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.nb{background:rgba(0,212,255,0.1);border:1px solid rgba(0,212,255,0.2);color:var(--accent);font-size:11px;font-weight:700;padding:4px 12px;border-radius:20px;}
.hero{position:relative;z-index:1;padding:50px 20px 30px;text-align:center;}
.ai{width:90px;height:90px;border-radius:22px;margin:0 auto 20px;display:block;border:2px solid rgba(0,212,255,0.3);box-shadow:0 0 30px rgba(0,212,255,0.2);object-fit:cover;}
.ey{font-size:11px;font-weight:700;letter-spacing:3px;color:var(--accent);text-transform:uppercase;margin-bottom:16px;}
.ht{font-family:'Bebas Neue',sans-serif;font-size:clamp(44px,10vw,80px);letter-spacing:6px;line-height:1;margin-bottom:10px;background:linear-gradient(135deg,#fff 30%,var(--accent));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.hs{font-size:clamp(13px,3vw,16px);color:var(--muted);max-width:500px;margin:0 auto 30px;line-height:1.6;}
.sr{display:flex;justify-content:center;gap:30px;margin:20px 0 30px;flex-wrap:wrap;}
.sn{text-align:center;}
.sv{font-family:'Bebas Neue',sans-serif;font-size:28px;letter-spacing:2px;color:var(--accent);}
.sk{font-size:11px;color:var(--muted);letter-spacing:1px;text-transform:uppercase;}
.pb{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin:0 20px 20px;position:relative;z-index:1;}
.pc{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:16px 20px;text-align:center;flex:1;max-width:180px;min-width:140px;}
.pc.ft{border-color:var(--accent);background:rgba(0,212,255,0.05);}
.pc.fr{border-color:var(--green);background:rgba(0,255,136,0.05);}
