.ss{display:flex;gap:12px;overflow-x:auto;padding-bottom:10px;scrollbar-width:none;}
.ss::-webkit-scrollbar{display:none;}
.sw{flex-shrink:0;width:140px;border-radius:16px;overflow:hidden;border:1px solid rgba(0,212,255,0.15);transition:transform 0.3s;cursor:pointer;background:var(--card);}
