.sl{padding:7px;font-size:10px;font-weight:700;color:var(--muted);text-align:center;letter-spacing:1px;text-transform:uppercase;}
.fg{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
.fc{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:16px;display:flex;align-items:flex-start;gap:12px;}
.fi{width:40px;height:40px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;}
