.fi.r{background:rgba(255,68,102,0.1);color:var(--accent2);}
.fi.g{background:rgba(0,255,136,0.1);color:var(--green);}
.fi.o{background:rgba(255,215,0,0.1);color:var(--gold);}
.fn{font-size:13px;font-weight:700;color:var(--text);margin-bottom:4px;}
.fd{font-size:11px;color:var(--muted);line-height:1.4;}
.cl{display:flex;flex-wrap:wrap;gap:8px;}
.cb{background:var(--card);border:1px solid var(--border);border-radius:8px;padding:8px 14px;font-size:12px;font-weight:600;color:var(--muted);display:flex;align-items:center;gap:6px;}
.cb.fr{border-color:rgba(0,255,136,0.3);color:var(--green);}
.cb .dot{width:6px;height:6px;border-radius:50%;background:var(--green);animation:blink 1s infinite;}
@keyframes blink{0%,100%{opacity:1;}50%{opacity:0.2;}}
.ib{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:20px;}
.ir{display:flex;justify-content:space-between;align-items:center;padding:10px 0;border-bottom:1px solid var(--border);}
.ir:last-child{border-bottom:none;padding-bottom:0;}
.ik{font-size:13px;color:var(--muted);}
.iv{font-size:13px;font-weight:600;}
.ctb{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:20px;}
.ci{display:flex;align-items:center;gap:14px;padding:12px 0;border-bottom:1px solid var(--border);text-decoration:none;color:var(--text);transition:color 0.2s;}
.ci:last-child{border-bottom:none;padding-bottom:0;}
.ci:hover{color:var(--accent);}
.cic{width:40px;height:40px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0;}
.cic.em{background:rgba(0,212,255,0.1);color:var(--accent);}
.cic.dv{background:rgba(255,215,0,0.1);color:var(--gold);}
.clb{font-size:12px;color:var(--muted);}
.cv{font-size:14px;font-weight:600;}
footer{text-align:center;padding:30px 20px;color:var(--muted);font-size:12px;border-top:1px solid var(--border);position:relative;z-index:1;}
footer span{color:var(--accent);}
.modal{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.92);z-index:1000;align-items:center;justify-content:center;}
.modal.active{display:flex;}
.modal img{max-width:90vw;max-height:90vh;border-radius:12px;}
